&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;at&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;#39;&lt;/span&gt;&lt;em&gt;&lt;strong&gt;In spite of all the honours that were heaped upon him, Pasteur remained a simple man ___(1)___ heart​&lt;/strong&gt;&lt;/em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;em&gt;&lt;em&gt;&lt;strong&gt;​&lt;/strong&gt;&lt;/em&gt;&amp;#39;&amp;#39;&lt;/em&gt;&lt;/span&gt;&lt;em&gt;&amp;nbsp;&lt;/em&gt;is&amp;nbsp;telling something about&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;the simplicity of Pasteur&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&amp;nbsp;&lt;/span&gt;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;the given&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;at&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;used&amp;nbsp;&lt;strong&gt;for stating what makes someone react in a particular way&lt;/strong&gt;.
		&lt;ul&gt;
			&lt;li&gt;&amp;#39;&amp;#39;&lt;strong&gt;At heart&lt;/strong&gt;&amp;#39;&amp;#39; means &lt;strong&gt;in one&amp;#39;s real nature, in contrast to how one may appear&lt;/strong&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;The preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;by&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;used &lt;strong&gt;for saying who or what does something&lt;/strong&gt;.
		&lt;ul&gt;
			&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;By&amp;nbsp;heart&lt;/span&gt;&amp;#39;&amp;#39; means&amp;nbsp;&lt;strong&gt;by remembering exactly; from memory&lt;/strong&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;The preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;in&amp;#39;&lt;/span&gt;&amp;nbsp;means&amp;nbsp;&lt;strong&gt;inside or to a position inside a particular area or object&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;The preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;on&amp;#39;&lt;/span&gt;&amp;nbsp;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;supported by, fixed to or touching something, especially a surface&lt;/strong&gt;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Conclusion:&amp;nbsp;&lt;/span&gt;Pasteur remained a simple man even though he got a large number of honours.&lt;/p&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;In spite of all the honours that were heaped upon him, Pasteur remained a simple man &lt;strong&gt;at&lt;/strong&gt; heart&lt;/em&gt;​​.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य &amp;#39;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;In spite of all the honours that were heaped upon him, Pasteur remained a simple man ___(1)___ heart​&lt;/span&gt;&lt;/em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;em&gt;​&lt;/em&gt;&lt;/span&gt;&amp;#39;&amp;#39; पाश्चर की सादगी के बारे में कुछ बता रहा है।&lt;/li&gt;
	&lt;li&gt;आइए दिए गए विकल्पों का पता लगाएं:
	&lt;ul&gt;
		&lt;li&gt;Preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;at&amp;#39;&lt;/span&gt;&amp;nbsp;का उपयोग यह बताने के लिए किया जाता है कि &lt;strong&gt;कोई व्यक्ति किसी विशेष तरीके से क्या प्रतिक्रिया करता है&lt;/strong&gt;।
		&lt;ul&gt;
			&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;At heart&lt;/span&gt;&amp;#39;&amp;#39; का अर्थ है &lt;strong&gt;किसी के वास्तविक स्वरूप में, इसके विपरीत कि कोई कैसे प्रकट हो सकता है&lt;/strong&gt;।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;Preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;by&amp;#39;&lt;/span&gt;&amp;nbsp;यह कहने के लिए प्रयोग किया जाता है कि &lt;strong&gt;कौन या क्या कुछ करता है&lt;/strong&gt;।
		&lt;ul&gt;
			&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;By heart&lt;/span&gt;&amp;#39;&amp;#39; का अर्थ है &lt;strong&gt;ठीक-ठीक याद करना; याद से&lt;/strong&gt;।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;Preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;in&amp;#39;&lt;/span&gt;&amp;nbsp;का अर्थ है &lt;strong&gt;किसी विशेष क्षेत्र या वस्तु के अंदर या स्थिति के अंदर&lt;/strong&gt;।&lt;/li&gt;
		&lt;li&gt;Preposition&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;on&amp;#39;&amp;nbsp;&lt;/span&gt;का अर्थ है&amp;nbsp;&lt;strong&gt;पर, के ऊपर&lt;/strong&gt;।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
&lt;span style=&quot;font-weight: 700;&quot;&gt;Conclusion:&lt;/span&gt;&amp;nbsp;इतने सारे सम्मानों के बावजूद, पाश्चर दिल से एक साधारण व्यक्ति बने रहे।&lt;/p&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1 है&lt;/span&gt;&amp;nbsp;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पुरा वाक्य&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&lt;/span&gt;&amp;nbsp;&lt;em&gt;In spite of all the honours that were heaped upon him, Pasteur remained a simple man&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;at&lt;/span&gt;&amp;nbsp;heart&lt;/em&gt;​​.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;drew&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence &amp;quot;&lt;strong&gt;&lt;em&gt;Perhaps the memories of his boyhood days, when he ___(2)___ the familiar scenes of his birthplace&lt;/em&gt;&lt;/strong&gt;...&amp;#39;&amp;#39;&amp;nbsp;is&amp;nbsp;telling something about&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;the memories of Pasteur&amp;#39;s boyhood days&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The given sentence is talking about &lt;strong&gt;the childhood days or about a past action&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the most appropriate word to be filled in the blank is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;drew&amp;#39;&lt;/span&gt;,&amp;nbsp;a past tense form of the verb.&lt;/li&gt;
	&lt;li&gt;The word &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;drew&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;to do a picture or diagram of something with a pencil, pen, etc. but not paint&lt;/strong&gt;.&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&lt;/span&gt;&lt;em&gt;&amp;nbsp;The artist &lt;strong&gt;drew&lt;/strong&gt; the scene from memory&lt;/em&gt;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;Perhaps the memories of his boyhood days, when he &lt;span style=&quot;font-weight: 700;&quot;&gt;drew&lt;/span&gt; the familiar scenes of his birthplace...&lt;/em&gt;&lt;br /&gt;
&amp;nbsp;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&lt;/span&gt;&amp;nbsp;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;&amp;nbsp;the other&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Drawn&lt;/span&gt;&amp;#39; is an adjective that means&amp;nbsp;&lt;strong&gt;looking tired, worried, or ill&lt;/strong&gt;.&amp;nbsp;(थका, चिंतित या बीमार-सा, लटका हुआ)&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Draw&lt;/span&gt;&amp;#39; is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the base form of the verb&lt;/span&gt;.&amp;nbsp;(&amp;#39;Draw&amp;#39; क्रिया का मूल रूप है)&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Draws&lt;/span&gt;&amp;#39; is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the third-person present singular form of the verb&lt;/span&gt;.&amp;nbsp;(&amp;#39;Draws&amp;#39; क्रिया का third-person present singular रूप है)&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;em&gt;Perhaps the memories of his boyhood days, when he ___(2)___ the familiar scenes of his birthplace&lt;/em&gt;&lt;/span&gt;...&amp;#39;&amp;#39; पाश्चर के बचपन के दिनों की यादों के बारे में कुछ बता रहा है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य &lt;strong&gt;बचपन के दिनों या पिछली कार्रवाई के बारे में बात कर रहा है&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;इसलिए, रिक्त स्थान में भरने के लिए सबसे उपयुक्त शब्द &amp;#39;&lt;strong&gt;drew&lt;/strong&gt;&amp;#39; है, जो &lt;strong&gt;क्रिया का भूतकाल&lt;/strong&gt; का रूप है।&lt;/li&gt;
	&lt;li&gt;शब्द &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;drew&lt;/span&gt;&amp;#39; का अर्थ है&amp;nbsp;&lt;strong&gt;किसी का चित्र या आरेख बनाना&lt;/strong&gt;।&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण:&lt;/span&gt;&amp;nbsp;&lt;em&gt;The artist&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;drew&lt;/span&gt;&amp;nbsp;the scene from memory&lt;/em&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 2 है&lt;/span&gt;&amp;nbsp;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पूर्ण वाक्य:&lt;/span&gt;&amp;nbsp;&lt;em&gt;Perhaps the memories of his boyhood days, when he&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;drew&lt;/span&gt;&amp;nbsp;the familiar scenes of his birthplace...&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;longing&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence &amp;quot;&lt;em&gt;&lt;strong&gt;Perhaps the memories of his boyhood days, when he drew the familiar scenes of his birthplace, and the ___(3)___ to be a great artist never wholly left him&lt;/strong&gt;&lt;/em&gt;&amp;#39;&amp;#39;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indicating&amp;nbsp;something about the artist in Pasteur&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The use of the&amp;nbsp;phrase &amp;#39;&amp;#39;&lt;strong&gt;never&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;left&lt;/span&gt;&amp;#39;&amp;#39; in the sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indicates&lt;/span&gt;&amp;nbsp;&lt;strong&gt;never went&amp;nbsp;away from&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the most appropriate word to be filled in the blank is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;longing&amp;#39;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The word &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;longing&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;a yearning desire&lt;/strong&gt;.&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&lt;/span&gt;&lt;em&gt;&amp;nbsp;She was &lt;strong&gt;longing&lt;/strong&gt; for some peace and privacy&lt;/em&gt;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;Perhaps the memories of his boyhood days, when he drew the familiar scenes of his birthplace, and the &lt;strong&gt;longing&lt;/strong&gt; to be a great artist never wholly left him&lt;/em&gt;&lt;em&gt;.&lt;/em&gt;&lt;br /&gt;
&amp;nbsp;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&lt;/span&gt;&amp;nbsp;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;&amp;nbsp;the other&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Itching&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;feeling a restless or strong desire to do something&lt;/strong&gt;.&amp;nbsp;(बेचैन या कुछ करने की तीव्र इच्छा महसूस करना)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Wishing&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;wanting to do something&lt;/strong&gt;.&amp;nbsp;(कुछ करने की चाह रखना, कुछ चाहना)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Loathing&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;feeling intense dislike or disgust for someone or something&lt;/strong&gt;.&amp;nbsp;(किसी व्&amp;zwj;यक्ति या वस्&amp;zwj;तु से नफ़रत करना)&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य &amp;quot;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Perhaps the memories of his boyhood days, when he drew the familiar scenes of his birthplace, and the ___(3)___ to be a great artist never wholly left him&lt;/span&gt;&lt;/em&gt;&amp;#39;&amp;#39;&amp;nbsp;पाश्चर के अंदर के कलाकार के बारे में कुछ बता रहा है।&lt;/li&gt;
	&lt;li&gt;वाक्य में phrase &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;never left&lt;/span&gt;&amp;#39;&amp;#39;&amp;nbsp;का प्रयोग यह इंगित करता है कि कभी दूर नहीं गया।&lt;/li&gt;
	&lt;li&gt;इसलिए, रिक्त स्थान में भरने के लिए सबसे उपयुक्त शब्द&amp;nbsp;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;longing&lt;/span&gt;&amp;#39;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Longing&lt;/span&gt;&amp;#39; शब्द का अर्थ&amp;nbsp;है &lt;strong&gt;लालसा, चाहत&lt;/strong&gt;।
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण:&lt;/span&gt;&amp;nbsp;&lt;em&gt;She was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;longing&lt;/span&gt;&amp;nbsp;for some peace and privacy&lt;/em&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3 है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पूर्ण वाक्य:&lt;/span&gt;&amp;nbsp;&lt;em&gt;Perhaps the memories of his boyhood days, when he drew the familiar scenes of his birthplace, and the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;longing&lt;/span&gt;&amp;nbsp;to be a great artist never wholly left him&lt;/em&gt;&lt;em&gt;.&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;become&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence &amp;quot;&lt;em&gt;&lt;strong&gt;He did ___(4)___ a great artist...&lt;/strong&gt;&lt;/em&gt;&amp;#39;&amp;#39;&amp;nbsp;is&amp;nbsp;telling &lt;strong&gt;something related to&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;a great artist&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;strong&gt;verb that follows &amp;#39;did&amp;#39;&lt;/strong&gt;&amp;nbsp;should be used &lt;strong&gt;in its base form&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;auxiliary verb &amp;#39;did&amp;#39;&lt;/strong&gt;&amp;nbsp;is marked &lt;strong&gt;for past tense&lt;/strong&gt;, but the &lt;strong&gt;main verb&lt;/strong&gt; is not and it appears &lt;strong&gt;in its base form&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the most appropriate word to be filled in the blank is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;become&amp;#39;&lt;/span&gt;, the base form of the verb.&lt;/li&gt;
	&lt;li&gt;The word &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;become&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;to begin to be something&lt;/strong&gt;.&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&lt;/span&gt;&lt;em&gt;&amp;nbsp;All these infants did &lt;strong&gt;become&lt;/strong&gt; healthy children with intact self-identity&lt;/em&gt;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;He did &lt;strong&gt;become&lt;/strong&gt; a great artist...&lt;/em&gt;&lt;br /&gt;
&amp;nbsp;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&lt;/span&gt;&amp;nbsp;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;&amp;nbsp;the other&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Became&lt;/span&gt;&amp;#39; is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the past tense form of the verb&lt;/span&gt;.&amp;nbsp;(&amp;#39;Became&amp;#39;&amp;nbsp;क्रिया का past tense रूप है)&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Becomes&lt;/span&gt;&amp;#39; is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the third-person present singular form of the verb&lt;/span&gt;.&amp;nbsp;(&amp;#39;Becomes&amp;#39;&amp;nbsp;क्रिया का third-person present singular रूप है)&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Becoming&lt;/span&gt;&amp;#39; is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;the gerund or present participle&amp;nbsp;form of the verb&lt;/span&gt;.&amp;nbsp;(&amp;#39;Becoming&amp;#39;&amp;nbsp;क्रिया का gerund or present participle रूप है)&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य &amp;quot;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;He did ___(4)___ a great artist...&lt;/span&gt;&lt;/em&gt;&amp;#39;&amp;#39; एक महान कलाकार से संबंधित कुछ बता रहा है।&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;strong&gt;Did&lt;/strong&gt;&amp;#39; &lt;strong&gt;के बाद आने वाली क्रिया&lt;/strong&gt; को उसके &lt;strong&gt;मूल रूप में&lt;/strong&gt; प्रयोग करना चाहिए।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Auxiliary verb&lt;/span&gt; &amp;#39;&lt;strong&gt;did&lt;/strong&gt;&amp;#39; &lt;strong&gt;भूतकाल &lt;/strong&gt;के लिए चिह्नित है, लेकिन &lt;strong&gt;मुख्य क्रिया&lt;/strong&gt; नहीं है और यह &lt;strong&gt;अपने मूल रूप में&lt;/strong&gt; प्रकट होती है।&lt;/li&gt;
	&lt;li&gt;इसलिए, रिक्त स्थान में भरने के लिए सबसे उपयुक्त शब्द&amp;nbsp;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;become&lt;/span&gt;&amp;#39;&amp;nbsp;है, जो क्रिया का मूल रूप है।&lt;/li&gt;
	&lt;li&gt;शब्द &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;become&lt;/span&gt;&amp;#39; का अर्थ है&amp;nbsp;&lt;strong&gt;कुछ हो जाना, कुछ बन जाना&lt;/strong&gt;।&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण:&lt;/span&gt;&amp;nbsp;&lt;em&gt;All these infants did&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;become&lt;/span&gt;&amp;nbsp;healthy children with intact self-identity&lt;/em&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1 है&lt;/span&gt;&amp;nbsp;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पूर्ण वाक्य:&lt;/span&gt;&amp;nbsp;&lt;em&gt;He did&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;become&lt;/span&gt;&amp;nbsp;a great artist...&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;abandoned&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence &amp;quot;&lt;strong&gt;&lt;em&gt;He did become&amp;nbsp;a great artist but after his sixteenth year he ___(5)___ the brush forever&lt;/em&gt;&lt;/strong&gt;&amp;#39;&amp;#39;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indicating&amp;nbsp;something happened after Pasteur&amp;#39;s sixteenth year&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The use of the&amp;nbsp;word &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;forever&lt;/span&gt;&amp;#39;&amp;#39; in the sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indicates&lt;/span&gt;&amp;nbsp;&lt;strong&gt;for all future time; for always&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the most appropriate word to be filled in the blank is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;abandoned&amp;#39;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The word &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;abandoned&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;to stop doing something without finishing it or without achieving what you wanted to do&lt;/strong&gt;.&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&lt;/span&gt;&lt;em&gt;&amp;nbsp;She &lt;strong&gt;abandoned&lt;/strong&gt; law for the fine arts&lt;/em&gt;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 4&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;He did become a great artist but after his sixteenth year he &lt;span style=&quot;font-weight: 700;&quot;&gt;abandoned&lt;/span&gt; the brush forever&lt;/em&gt;&lt;em&gt;.&lt;/em&gt;&lt;br /&gt;
&amp;nbsp;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&lt;/span&gt;&amp;nbsp;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;&amp;nbsp;the other&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Discharged&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;allowed somebody officially to leave; sent somebody away&lt;/strong&gt;.&amp;nbsp;(किसी को&amp;nbsp;बाहर या दूर भेज देना या मुक्त कर देना)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Released&lt;/span&gt;&amp;#39; means&lt;strong&gt;&amp;nbsp;to stop holding something so that it can move, fly, fall, etc. freely&lt;/strong&gt;.&amp;nbsp;(किसी वस्&amp;zwj;तु को खुला छोड़ देना, बंधन ढीला करना)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Expelled&lt;/span&gt;&amp;#39; means&amp;nbsp;&lt;strong&gt;forced somebody to leave a country, school, club, etc&lt;/strong&gt;.&amp;nbsp;(निष्&amp;zwj;कासित करना)&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;em&gt;He did become&amp;nbsp;a great artist but after his sixteenth year he ___(5)___ the brush forever&lt;/em&gt;&lt;/span&gt;&amp;#39;&amp;#39;&amp;nbsp;यह संकेत दे रहा है कि पाश्चर के सोलहवें वर्ष के बाद कुछ हुआ था।&lt;/li&gt;
	&lt;li&gt;वाक्य में शब्द &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;forever&lt;/span&gt;&amp;#39;&amp;#39; का प्रयोग,&amp;nbsp;&lt;strong&gt;भविष्य के समय के लिए&lt;/strong&gt; इंगित करता है; &lt;strong&gt;हमेशा के लिए&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;इसलिए, रिक्त स्थान में भरने के लिए सबसे उपयुक्त शब्द&amp;nbsp;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;abandoned&lt;/span&gt;&amp;#39;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Abandoned&lt;/span&gt;&amp;#39; शब्द का अर्थ&amp;nbsp;है &lt;strong&gt;किसी काम को अधूरा या उद्देश्&amp;zwj;य प्राप्&amp;zwj;त किए बिना बीच में ही रोक देना&lt;/strong&gt;।
	&lt;ul&gt;
