&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present perfect tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;have + been + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;verified&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;has +&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;V3 (verified)&lt;/span&gt;&amp;quot;&amp;nbsp;में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present perfect tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;delegate&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Let us explore the marked&amp;nbsp;option:&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;Delegate&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;to give one&amp;rsquo;s authority to another&lt;/strong&gt;. (किसी एक व्यक्ति का अधिकार,&amp;nbsp;कार्य या जिम्मेदारी दूसरे को सौंपना)

		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;He plans to &lt;strong&gt;delegate&lt;/strong&gt; more authority to his deputies&lt;/em&gt;.&lt;br /&gt;
			&amp;nbsp;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;&lt;i&gt;.&lt;/i&gt;&lt;br /&gt;
&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Let us explore the other options:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;Shirk&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;to avoid doing something that is difficult or unpleasant, especially because you are too lazy&lt;/strong&gt;.&amp;nbsp;(कठिन या अप्रिय काम से जी चुराना; टालना)

		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;The Government will not &lt;strong&gt;shirk&lt;/strong&gt; from considering the need for further action&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Usurp&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;to take somebody&amp;rsquo;s position and power without having the right to do this&lt;/strong&gt;.&amp;nbsp;(किसी के पद और या शक्ति को हड़प लेना)
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;The vice - president is trying to &lt;strong&gt;usurp&lt;/strong&gt; the president&amp;#39;s authority&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;Supervise&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;to watch somebody or something to make sure that work is being done properly or that people are behaving correctly&lt;/strong&gt;.&amp;nbsp;(देखभाल करना, निगरानी करना)
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;An executive officer was appointed to &lt;strong&gt;supervise&lt;/strong&gt; the arrangements&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;had tried harder&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the underlined segment, the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;use of the present form of the verb &amp;#39;have&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect &lt;/span&gt;and&amp;nbsp;the &lt;strong&gt;use of the word&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; &amp;#39;more&amp;#39; is superfluous&amp;nbsp;&lt;/span&gt;or&lt;span style=&quot;font-weight: 700;&quot;&gt; not required&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;To refer to a &lt;strong&gt;past wish (&lt;/strong&gt;here, &lt;strong&gt;wished&lt;/strong&gt;), we use a &lt;strong&gt;past perfect verb after the object&amp;nbsp;&lt;/strong&gt;and to form the &lt;strong&gt;past perfect&lt;/strong&gt;, use &amp;#39;&lt;strong&gt;had&lt;/strong&gt;&amp;#39;&amp;nbsp;&lt;strong&gt;followed by a past participle verb&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the &lt;strong&gt;past tense form of the verb &amp;#39;had&amp;#39;&lt;/strong&gt; should be used &lt;strong&gt;in place of&lt;/strong&gt; the verb &lt;strong&gt;&amp;#39;have&amp;#39;&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Also, the &lt;strong&gt;comparative form of the adverb &amp;#39;hard&amp;#39;&lt;/strong&gt; is &amp;#39;&lt;strong&gt;harder&lt;/strong&gt;&amp;#39;,&amp;nbsp;not &amp;#39;&amp;#39;&lt;strong&gt;more harder&lt;/strong&gt;&amp;#39;&amp;#39;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;comparative form &amp;#39;harder&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;&amp;#39;&amp;#39;&lt;strong&gt;more harder&lt;/strong&gt;&amp;#39;&amp;#39;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;I wished I &lt;strong&gt;had tried harder&lt;/strong&gt;&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;रेखांकित खण्ड में &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;have&amp;#39;&lt;/span&gt; क्रिया के वर्तमान रूप का प्रयोग गलत है और &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;more&amp;#39;&lt;/span&gt; शब्द का प्रयोग अतिश्योक्तिपूर्ण है या आवश्यक नहीं है।&lt;/li&gt;
	&lt;li&gt;एक अतीत की इच्छा (यहाँ, wished) को संदर्भित करने के लिए, हम वस्तु के बाद एक past perfect verb का उपयोग करते हैं और past perfect बनाने के लिए, &amp;#39;had&amp;#39; का उपयोग करते हैं, उसके बाद एक past participle verb&amp;nbsp;का उपयोग करते हैं।&lt;/li&gt;
	&lt;li&gt;इसलिए, past tense form of the verb &amp;#39;had&amp;#39; का प्रयोग verb &amp;#39;have&amp;#39; के स्थान पर किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;साथ ही, comparative form of the adverb &amp;#39;hard&amp;#39;, &amp;#39;harder&amp;#39; है, न कि &amp;#39;more harder&amp;#39;।&lt;/li&gt;
	&lt;li&gt;इसलिए, &amp;#39;more harder&amp;#39; के स्थान पर comparative form &amp;#39;harder&amp;#39; का प्रयोग किया जाना चाहिए।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3 &lt;/span&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&lt;/span&gt;&amp;nbsp;&lt;em&gt;I wished I&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;had tried harder&lt;/span&gt;&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;need not&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence is saying &lt;strong&gt;something related to carrying books to school&lt;/strong&gt;. (दिया गया वाक्य स्कूल में किताबें ले जाने से संबंधित कुछ कह रहा है)&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Need not&lt;/span&gt;&amp;nbsp;means&amp;nbsp;&lt;strong&gt;something not needed&lt;/strong&gt;.&amp;nbsp;(किसी चीज की जरूरत ना होना)
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&lt;/span&gt;&lt;em&gt;&amp;nbsp;You &lt;strong&gt;need not&lt;/strong&gt; worry about anything&lt;/em&gt;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Conclusion:&lt;/span&gt;&amp;nbsp;No need of carrying all the books to school daily. (रोजाना स्कूल में किताबें ना ले जाने की जरूरत)&lt;/p&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 4&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;You &lt;span style=&quot;font-weight: 700;&quot;&gt;need not&lt;/span&gt;&lt;em&gt; &lt;/em&gt;carry all the books to school daily&lt;/em&gt;.&lt;br /&gt;
&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&lt;/span&gt;&amp;nbsp;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;the other&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Ought not&lt;/span&gt;&amp;#39;&amp;#39;&amp;nbsp;is&amp;nbsp;used &lt;strong&gt;to indicate what is not expected&lt;/strong&gt;.&amp;nbsp;(क्या अपेक्षित नहीं है)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Would not&lt;/span&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is&amp;nbsp;used &lt;strong&gt;to say that someone refused to do something&lt;/strong&gt;.&amp;nbsp;(किसी ने कुछ करने से मना कर दिया)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Have not&lt;/span&gt;&amp;#39;&amp;#39;&amp;nbsp;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;not&amp;nbsp;&lt;/span&gt;&lt;strong&gt;to&amp;nbsp;own or&amp;nbsp;hold something; not to possess&lt;/strong&gt;. (किसी वस्&amp;zwj;तु का मालिक ना होना या किसी बात का अधिकारी ना होना; किसी वस्&amp;zwj;तु पर अधिकार ना रखना)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;strong&gt;He said to you, &amp;ldquo;I did not know that it is your birthday today.&amp;rdquo;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is an&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;basic rules&lt;/span&gt;&amp;nbsp;for changing or&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converting indirect speech into direct speech:&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;commas,&amp;nbsp;inverted commas&lt;/span&gt;&amp;nbsp;are&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;added&lt;/span&gt;, and&lt;span style=&quot;font-weight: 700;&quot;&gt; &amp;#39;that&amp;#39; &lt;/span&gt;is &lt;strong&gt;removed&lt;/strong&gt;,&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;told&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;replaced by &amp;#39;said to&amp;#39;&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;The &lt;strong&gt;third-person&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;pronoun &amp;#39;he&amp;#39;&amp;nbsp;&lt;/span&gt;will be changed into the &lt;span style=&quot;font-weight: 700;&quot;&gt;first-person&amp;nbsp;pronoun&amp;nbsp;&amp;#39;I&amp;#39;&amp;nbsp;&lt;/span&gt;and&lt;span style=&quot;font-weight: 700;&quot;&gt; &amp;#39;&amp;#39;that day&amp;#39;&amp;#39;&amp;nbsp;&lt;/span&gt;becomes&lt;span style=&quot;font-weight: 700;&quot;&gt; &amp;#39;today&amp;#39;&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past perfect tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ had + V3 (known)&amp;nbsp;+&amp;nbsp;Object&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;will be changed into&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past simple tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V2 (did + know) +&amp;nbsp;Object&lt;/span&gt;&amp;#39;.&lt;/li&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V2 (was)&amp;nbsp;+ Object&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;will be changed into&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;format &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V1 (is)&amp;nbsp;+ Object&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;From the following rules, we get the&amp;nbsp;correct sentence&amp;nbsp;as&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The following table will enable us to know how tense changes&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;into Indirect speech&lt;/span&gt;:

	&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; dir=&quot;ltr&quot; style=&quot;width: 0px; border: none;&quot; xmlns=&quot;http://www.w3.org/1999/xhtml&quot;&gt;
		&lt;colgroup&gt;
			&lt;col width=&quot;422&quot; /&gt;
			&lt;col width=&quot;445&quot; /&gt;
		&lt;/colgroup&gt;
		&lt;tbody&gt;
			&lt;tr style=&quot;height: 21px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Direct Speech&amp;quot;}&quot; style=&quot;padding: 2px 3px; border: 1px solid rgb(0, 0, 0); overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Direct Speech&lt;/span&gt;&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Indirect Speech&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Indirect Speech&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present simple  (Subject +V1st + Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present simple (Subject +V1st + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject +V2 + Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past simple (Subject +V2 + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 28px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present continuous (Subject +is/am/are+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present continuous (Subject +is/am/are+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past Continuous (Subject +was/were+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present perfect (Subject + has/have+V3+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present perfect (Subject + has/have+V3+Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect (Subject+had+V3+Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 25px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject+V2+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past simple (Subject+V2+Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect (Subject+had+V3+Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past Continuous (Subject +was/were+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect continuous (Subject +had been+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect continuous (Subject +had been+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 26px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future simple (Subject+ will/shall+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future simple (Subject+ will/shall+V1+object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Conditional (Subject+ would+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present Conditional (Subject+ would+V1+object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 29px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Indirect speech&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;&amp;nbsp;में बदलने या बदलने के लिए बुनियादी नियम:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Commas,&amp;nbsp;inverted commas&lt;/span&gt; जोड़े जाते हैं, और &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;that&lt;/span&gt;&amp;#39; हटा दिया जाता है, &amp;#39;&lt;strong&gt;said to&lt;/strong&gt;&amp;#39; को &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;told&lt;/span&gt;&amp;#39; से बदल दिया जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Third-person&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;pronoun &amp;#39;he&amp;#39;&lt;/span&gt;, &lt;span style=&quot;font-weight: 700;&quot;&gt;first-person&amp;nbsp;pronoun&amp;nbsp;&amp;#39;I&amp;#39;&lt;/span&gt; बन जाता है और &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;that day&lt;/span&gt;&amp;#39;, &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;today&lt;/span&gt;&amp;#39; बन जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Past perfect tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;Subject&amp;nbsp;+ had + V3 (known)&amp;nbsp;+&amp;nbsp;Object&amp;#39;&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past&amp;nbsp;simple tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V2 (did + know) +&amp;nbsp;Object&lt;/span&gt;&amp;#39;&amp;nbsp;में बदल दिया जाएगा।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Past simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;Subject&amp;nbsp;+ V2 (was)&amp;nbsp;+ Object&amp;#39;&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V1 (is)&amp;nbsp;+ Object&lt;/span&gt;&amp;#39;&amp;nbsp;में बदल दिया जाएगा।&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 2 है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;continuously&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Given Idiom:&amp;nbsp;&lt;/span&gt;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;At a stretch&lt;/span&gt;&lt;/em&gt;&amp;nbsp;means&amp;nbsp;&lt;strong&gt;continuously; without stopping&lt;/strong&gt;. (लगातार; बिना रुके)

	&lt;ul&gt;
		&lt;li&gt;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&amp;nbsp;&lt;/span&gt;She worked for six hours &lt;strong&gt;at a stretch&lt;/strong&gt;&lt;/em&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;From the given options, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;fourth option&lt;/span&gt;&amp;nbsp;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;most appropriate meaning of the given idiom.&lt;/span&gt;&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 4&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;We may think from the phrase &amp;quot;At a stretch&amp;quot;&amp;nbsp;that&amp;nbsp;it is all about straightening or extending one&amp;#39;s body or a part of one&amp;#39;s body.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;
	&lt;p&gt;&lt;em&gt;This idiom, first recorded in 1774, does not imply being seated while engaging in a single continuous activity.&amp;nbsp;Rather, it transfers the meaning of stretch as &amp;#39;&amp;#39;a continuous length&amp;#39;&amp;#39; to &amp;#39;&amp;#39;a continuous time period.&amp;#39;&amp;#39;&lt;/em&gt;&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;They were giving a face-lift to the entire area&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is in&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&amp;nbsp;&lt;/span&gt;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past continuous&amp;nbsp;tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;When we convert this sentence into an&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;, the subject &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;The entire area&lt;/span&gt;&amp;#39; of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive&amp;nbsp;voice&lt;/span&gt;&amp;nbsp;becomes the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;object&lt;/span&gt;, the &lt;strong&gt;hidden&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;them&lt;/span&gt;&amp;#39; becomes the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject &amp;#39;They&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The passive format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;was + being + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;given&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the active format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;were +&lt;/span&gt;&amp;nbsp;&lt;strong&gt;present participle form of the verb&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;(giving)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;active and passive voice&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past continuous tense&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 1&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Verbs of passive format have a different set of tenses (*V3 - Past participle or Third form of the Verb) as given below in the table:&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; dir=&quot;ltr&quot; style=&quot;background-color: rgb(255, 255, 255); width: 330px;&quot; xmlns=&quot;http://www.w3.org/1999/xhtml&quot;&gt;
	&lt;colgroup&gt;
		&lt;col width=&quot;183&quot; /&gt;
		&lt;col width=&quot;221&quot; /&gt;
		&lt;col width=&quot;156&quot; /&gt;
		&lt;col width=&quot;246&quot; /&gt;
	&lt;/colgroup&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;           TENSE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;TENSE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;            ACTIVE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ACTIVE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;          PASSIVE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;PASSIVE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;      PASSIVE CONVERSION&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;PASSIVE CONVERSION&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Simple&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Simple&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He plays football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He plays football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;am/is/are + V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;am/is/are + V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football is played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Continuous&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Continuous&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He is playing football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He is playing football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;am/is/are + being +V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;am/is/are + being +V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football is being played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football is being played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Perfect&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Perfect&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He has played football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He has played football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Has/have + been+ V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Has/have + been+ V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football has been played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football has been played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Perfect Continuous&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Perfect Continuous&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He has been playing football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He has been playing football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Not used and unusual.&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Not used and unusual.&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Not used and unusual&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Not used and unusual&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Simple&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past Simple&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He played football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He played football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Was/were + V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Was/were + V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football was played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football was played by him&lt;/td&gt;
