&lt;p&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past continuous&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;जब हम इस वाक्य को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;में बदलते हैं, तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;का&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;The entire area&amp;#39;&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&lt;/span&gt;&amp;nbsp;बन जाता है&amp;nbsp;और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;hidden&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;them&lt;/span&gt;&amp;#39;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;They&amp;#39;&amp;nbsp;&lt;/span&gt;बन जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;was + being + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;given&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;were +&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present participle form of the verb&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;(giving)&lt;/span&gt;&amp;quot;&amp;nbsp;में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past continuous&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;Let these books be sent to my new address&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The given sentence is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V1 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;send&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;be + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;sent&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 2.&lt;/span&gt;&lt;/p&gt;

