&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;&amp;nbsp;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;&amp;nbsp;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V1 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;send&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;be + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;sent&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 2&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;strong&gt;She said that she would finish reading the novel that day&lt;/strong&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;basic rules&lt;/span&gt;&amp;nbsp;for changing or&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converting direct speech into indirect speech:&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;commas, inverted commas&lt;/span&gt;&amp;nbsp;are&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;removed,&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;that&lt;/span&gt;&amp;#39; is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;added&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;The first-person pronoun &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;I&lt;/span&gt;&amp;#39; becomes the third-person pronoun &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;s&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;he&lt;/span&gt;&amp;#39; and &amp;#39;&lt;strong&gt;today&lt;/strong&gt;&amp;#39; becomes &amp;#39;&amp;#39;&lt;strong&gt;that day&lt;/strong&gt;&amp;#39;&amp;#39;.&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;The&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;present simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+&amp;nbsp;V&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;1&lt;/span&gt;&amp;nbsp;(will)&amp;nbsp;+ Object&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;will be changed into&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past&amp;nbsp;simple tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&amp;nbsp;&lt;/span&gt;(would)&amp;nbsp;+&amp;nbsp;Object&lt;/span&gt;&amp;#39;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;You may think reporting verb&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;#39;would finish&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;should be used.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Option 3&amp;nbsp;&lt;/span&gt;&amp;amp;&lt;span style=&quot;font-weight: 700;&quot;&gt; 4&lt;/span&gt;&amp;nbsp;are&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;wrong&amp;nbsp;&lt;/span&gt;because &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;would finish&lt;/span&gt;&amp;#39; is used&amp;nbsp;in the present conditional tense of the indirect speech.&lt;/li&gt;
	&lt;li&gt;Thus, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

