			&lt;tr style=&quot;height: 26px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future simple (Subject+ will/shall+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future simple (Subject+ will/shall+V1+object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Conditional (Subject+ would+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present Conditional (Subject+would+V1+object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 29px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Direct speech&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indirect speech&lt;/span&gt;&amp;nbsp;में बदलने या बदलने के लिए बुनियादी नियम:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Commas, inverted commas&amp;nbsp;&lt;/span&gt;हटा दिए जाते हैं और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;that&amp;#39;&lt;/span&gt;&amp;nbsp;जोड़ा जाता है।&lt;/li&gt;
		&lt;li&gt;First-person pronoun &amp;#39;&lt;strong&gt;I&lt;/strong&gt;&amp;#39;, third-person pronoun &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;s&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;he&lt;/span&gt;&amp;#39; बन जाता है और &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;today&lt;/span&gt;&amp;#39;, &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;that day&lt;/span&gt;&amp;#39; बन जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Present simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+&amp;nbsp;V&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;1&lt;/span&gt;&amp;nbsp;(will)&amp;nbsp;+ Object&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past&amp;nbsp;simple tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&amp;nbsp;&lt;/span&gt;(would)&amp;nbsp;+&amp;nbsp;Object&lt;/span&gt;&amp;#39;&amp;nbsp;में बदल दिया जाएगा।&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3 है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;soliloquy&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Let us explore the marked&amp;nbsp;option:&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;Soliloquy&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;a speech expressing one&amp;rsquo;s thoughts aloud to oneself&lt;/strong&gt;. (अपने विचारों को ज़ोर से व्यक्त करने वाला भाषण)

		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;The actress&amp;rsquo;s &lt;strong&gt;soliloquy&lt;/strong&gt; lets the audience hear the character&amp;rsquo;s inner thoughts right before the climax&lt;/em&gt;.&lt;br /&gt;
			&amp;nbsp;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;&lt;i&gt;.&lt;/i&gt;&lt;br /&gt;
&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Let us explore the other options:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;Harangue&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;to speak in a loud and angry way, often for a long time, in order to criticize somebody or something or to try to persuade people to do something&lt;/strong&gt;.&amp;nbsp;(उग्र या जोशीला भाषण देना)

		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;We had to listen to a long &lt;strong&gt;harangue&lt;/strong&gt; about our own shortcomings&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;Hyperbole&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;a way of speaking or writing that makes something sound better, more exciting, dangerous, etc. than it really is&lt;/strong&gt;.&amp;nbsp;(किसी वस्&amp;zwj;तु की विशेषता को बढ़ा-चढ़ाकर बखान करने का ढंग, अतिशयोक्तिपूर्ण कथन)
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;I can say without &lt;strong&gt;hyperbole&lt;/strong&gt; this is the greatest meal I have ever had!&lt;/em&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;S&lt;/span&gt;&lt;strong&gt;acrilege&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;treating a religious object or place without the respect that it deserves&lt;/strong&gt;.&amp;nbsp;(पवित्र वस्&amp;zwj;तु या स्&amp;zwj;थान का अपमान; अपवित्रीकरण)
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;The cult of the Roman emperor was &lt;strong&gt;sacrilege&lt;/strong&gt; to Jews and Christians&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;Are the authorities relaxing the attendance rules?&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline;  -space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is in&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&amp;nbsp;&lt;/span&gt;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present continuous tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;When we convert this sentence into an&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;, the subject &amp;#39;&lt;strong&gt;the attendance rules&lt;/strong&gt;&amp;#39; of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive&amp;nbsp;voice&lt;/span&gt;&amp;nbsp;becomes the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;object&lt;/span&gt;, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;the authorities&lt;/span&gt;&amp;#39; becomes the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The passive format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;are + being + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;relaxed&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the active format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;are +&lt;/span&gt;&amp;nbsp;&lt;strong&gt;present participle form of the verb&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(relaxing)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;active and passive voice&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present continuous tense&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 4&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Verbs of passive format have a different set of tenses (*V3 - Past participle or Third form of the Verb) as given below in the table:&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; dir=&quot;ltr&quot; style=&quot;background-color:  (255, 255, 255); width: 330px;&quot; xmlns=&quot;http://www.w3.org/1999/xhtml&quot;&gt;
	&lt;colgroup&gt;
		&lt;col width=&quot;183&quot; /&gt;
		&lt;col width=&quot;221&quot; /&gt;
		&lt;col width=&quot;156&quot; /&gt;
		&lt;col width=&quot;246&quot; /&gt;
	&lt;/colgroup&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;           TENSE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;TENSE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;            ACTIVE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ACTIVE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;          PASSIVE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;PASSIVE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;      PASSIVE CONVERSION&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;PASSIVE CONVERSION&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Simple&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Simple&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He plays football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He plays football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;am/is/are + V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;am/is/are + V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football is played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Continuous&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Continuous&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He is playing football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He is playing football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;am/is/are + being +V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;am/is/are + being +V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football is being played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football is being played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Perfect&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Perfect&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He has played football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He has played football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Has/have + been+ V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Has/have + been+ V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football has been played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football has been played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Perfect Continuous&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Perfect Continuous&lt;/td&gt;
