&lt;p&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present continuous tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;जब हम इस वाक्य को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;में बदलते हैं, तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;का&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;the attendance rules&amp;#39;&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&lt;/span&gt;&amp;nbsp;बन जाता है&amp;nbsp;और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object &amp;#39;the authorities&amp;#39;&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;बन जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;are + being + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;relaxed&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;are +&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present participle form of the verb&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(relaxing)&lt;/span&gt;&amp;quot;&amp;nbsp;में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present continuous tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 4&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;me whether I had seen&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;superfluous&amp;nbsp;&lt;/span&gt;or&lt;span style=&quot;font-weight: 700;&quot;&gt; not required&amp;nbsp;&lt;/span&gt;and&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;that&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt;&amp;nbsp;means&amp;nbsp;&lt;strong&gt;showing that somebody or something is taken away, removed, or separated from somebody or something else&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The given sentence is &lt;strong&gt;expressing doubt between two or more possibilities&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;that&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;used &lt;strong&gt;for&amp;nbsp;introducing a subordinate clause expressing a statement or hypothesis&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;whether&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;that&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;whether&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;used &lt;strong&gt;for expressing a choice or doubt between two or more possibilities&lt;/strong&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;She asked &lt;strong&gt;me whether I had seen&lt;/strong&gt;&lt;/em&gt;&lt;em&gt; the movie or not&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में, &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&amp;nbsp;&lt;/span&gt;का प्रयोग अतिश्योक्तिपूर्ण है या आवश्यक नहीं है और &lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;that&amp;#39;&lt;/span&gt; गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Preposition &amp;#39;from&amp;#39;&lt;/span&gt; का अर्थ है किसी व्&amp;zwj;यक्ति या वस्&amp;zwj;तु का किसी अन्&amp;zwj;य व्&amp;zwj;यक्ति या वस्&amp;zwj;तु से अलग होने या किए जाने का सूचक; से।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य दो या दो से अधिक संभावनाओं के बीच संदेह व्यक्त कर रहा है।&lt;/li&gt;
	&lt;li&gt;एक बयान या परिकल्पना व्यक्त करने वाले subordinate clause को पेश करने के लिए conjunction &amp;#39;that&amp;#39; का उपयोग किया जाता है।&lt;/li&gt;
	&lt;li&gt;इसलिए,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;that&amp;#39;&lt;/span&gt;&amp;nbsp;के स्थान पर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;whether&amp;#39;&lt;/span&gt;&amp;nbsp;का प्रयोग किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;दो या दो से अधिक संभावनाओं के बीच एक विकल्प या संदेह व्यक्त करने के लिए &lt;span style=&quot;font-weight: 700;&quot;&gt;conjunction &amp;#39;whether&amp;#39;&lt;/span&gt; का उपयोग किया जाता है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;She asked&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;me whether I had seen&lt;/span&gt;&lt;/em&gt;&lt;em&gt;&amp;nbsp;the movie or not&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;She was advised a week&amp;rsquo;s rest by the doctor&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The given sentence is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past simple tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;When we convert this sentence into a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;, the subject &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;The doctor&lt;/span&gt;&amp;#39; of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;becomes the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;object&lt;/span&gt;, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;her&lt;/span&gt;&amp;#39; becomes the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject &amp;#39;She&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V2 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;advised&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;was&amp;nbsp;+ V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;advised&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past simple tense&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 1.&lt;/span&gt;&lt;/p&gt;

