			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Direct Speech&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Direct Speech&lt;/strong&gt;&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Indirect Speech&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Indirect Speech&lt;/strong&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present simple  (Subject +V1st + Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present simple (Subject +V1st + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject +V2 + Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past simple (Subject +V2 + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 28px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present continuous (Subject +is/am/are+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present continuous (Subject +is/am/are+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past Continuous (Subject +was/were+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present perfect (Subject + has/have+V3+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present perfect (Subject + has/have+V3+Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect (Subject+had+V3+Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 25px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject+V2+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past simple (Subject+V2+Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect (Subject+had+V3+Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past Continuous (Subject +was/were+V1+ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect continuous (Subject +had been+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect continuous (Subject+had been+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 26px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future simple (Subject+ will/shall+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future simple (Subject+ will/shall+V1+object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Conditional (Subject+ would+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present Conditional (Subject+would+V1+object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 29px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Direct speech&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indirect speech&lt;/span&gt;&amp;nbsp;में बदलने या बदलने के लिए बुनियादी नियम:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Commas, inverted commas,&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;exclamation mark (!)&amp;nbsp;&lt;/span&gt;हटा दिए जाते हैं और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;that&amp;#39;&lt;/span&gt;&amp;nbsp;जोड़ा जाता है।&lt;/li&gt;
		&lt;li&gt;Exclamation mark &amp;#39;&amp;#39;What a pity!&amp;#39;&amp;#39; बन जाता है &amp;#39;&amp;#39;it was a pity&amp;#39;&amp;#39;।&lt;/li&gt;
		&lt;li&gt;Second-person pronoun &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;You&lt;/span&gt;&amp;#39;, first-person pronoun &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;I&lt;/span&gt;&amp;#39; बन जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Past simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;Subject&amp;nbsp;+&amp;nbsp;V&lt;/span&gt;&lt;span style=&quot;font-weight: 700; position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(missed)&amp;nbsp;+ Object&amp;#39;&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past&amp;nbsp;perfect tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ had + V&lt;/span&gt;&lt;span style=&quot;font-weight: 700; position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;3&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(missed)&amp;nbsp;+&amp;nbsp;Object&lt;/span&gt;&amp;#39;&amp;nbsp;में बदल दिया जाएगा।&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3 है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;Those who want&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;They&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;and&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;singular form of the verb &amp;#39;wants&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;They&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;used to refer to &lt;strong&gt;two or more people or things previously mentioned or easily identified&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;Those&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;They&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;Those&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;used &lt;strong&gt;in singling out someone or something&lt;/strong&gt;&lt;strong&gt; and ascribing a distinctive feature to them&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Also, the &lt;strong&gt;plural form of the verb&lt;/strong&gt; should be used &lt;strong&gt;with the plural subject&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;plural form of the verb&amp;nbsp;&amp;#39;want&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;singular form of the verb &amp;#39;wants&amp;#39;&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;&lt;strong&gt;Those who want&lt;/strong&gt;&amp;nbsp;to play should leave the class&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में &lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;They&amp;#39;&lt;/span&gt; का प्रयोग और &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;wants&amp;#39;&lt;/span&gt; क्रिया का एकवचन रूप गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Pronoun &amp;#39;They&amp;#39;&lt;/span&gt; का प्रयोग दो या दो से अधिक लोगों या पहले बताई गई या आसानी से पहचानी जाने वाली चीजों को संदर्भित करने के लिए किया जाता है।&lt;/li&gt;
	&lt;li&gt;इसलिए,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;They&amp;#39;&lt;/span&gt;&amp;nbsp;के स्थान पर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;pronoun &amp;#39;Those&amp;#39;&lt;/span&gt;&amp;nbsp;के ठीक बाद आना चाहिए।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Pronoun &amp;#39;Those&amp;#39;&lt;/span&gt; का प्रयोग किसी व्यक्ति या वस्तु को अलग करने और उन्हें एक विशिष्ट विशेषता बताने के लिए किया जाता है।&lt;/li&gt;
	&lt;li&gt;साथ ही, &lt;span style=&quot;font-weight: 700;&quot;&gt;verb&lt;/span&gt; के बहुवचन रूप का प्रयोग बहुवचन &lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt; के साथ किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;इसलिए,&amp;nbsp;क्रिया के एकवचन रूप &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;wants&amp;#39;&amp;nbsp;&lt;/span&gt;के स्थान पर&amp;nbsp;क्रिया के बहुवचन रूप &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;want&amp;#39;&amp;nbsp;&lt;/span&gt;का प्रयोग करना चाहिए।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Those who want&lt;/span&gt;&amp;nbsp;to play should leave the class&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;didn&amp;#39;t he&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence is a&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;tag question&lt;/span&gt;.&amp;nbsp;We use&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;tag questions to ask for confirmation&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;A&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;positive sentence takes a negative tag&lt;/span&gt;&amp;nbsp;and a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;negative sentence takes a positive tag&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The given sentence is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;a positive statement&lt;/span&gt;&amp;nbsp;and&amp;nbsp;therefore, &lt;span style=&quot;font-weight: 700;&quot;&gt;a negative tag&amp;nbsp;&lt;/span&gt;should be used, also, the given sentence is in the &lt;strong&gt;past tense&lt;/strong&gt;, therefore, the &lt;strong&gt;tag should be in the past tense&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;negative tag &amp;#39;didn&amp;#39;t&amp;#39;&lt;/span&gt;&amp;nbsp;should be used in place of the positive tag &lt;strong&gt;&amp;#39;did&amp;#39;&lt;/strong&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;He promised to deliver the goods yesterday, &lt;strong&gt;didn&amp;#39;t&amp;nbsp;he&lt;/strong&gt;?&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य एक टैग प्रश्न है। पुष्टि के लिए पूछने के लिए हम टैग प्रश्नों का उपयोग करते हैं।&lt;/li&gt;
	&lt;li&gt;एक सकारात्मक वाक्य एक नकारात्मक टैग लेता है और एक नकारात्मक वाक्य एक सकारात्मक टैग लेता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य एक सकारात्मक कथन है और इसलिए, एक नकारात्मक टैग का उपयोग किया जाना चाहिए, साथ ही, दिया गया वाक्य भूत काल में है, इसलिए, टैग भूत काल में होना चाहिए।&lt;/li&gt;
	&lt;li&gt;इसलिए, सकारात्मक टैग &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;did&amp;#39;&lt;/span&gt; के स्थान पर नकारात्मक टैग &lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;didn&amp;#39;t&amp;#39;&lt;/span&gt; का उपयोग किया जाना चाहिए।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;He promised to deliver the goods yesterday,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;didn&amp;#39;t&amp;nbsp;he&lt;/span&gt;?&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;strong&gt;The teacher said that too many cooks spoil the broth&lt;/strong&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&lt;strong&gt;&amp;nbsp;given sentence&lt;/strong&gt;&amp;nbsp;is a&amp;nbsp;&lt;strong&gt;direct speech.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;strong&gt;basic rules&lt;/strong&gt;&amp;nbsp;for changing or&amp;nbsp;&lt;strong&gt;converting direct speech into indirect speech:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;&lt;strong&gt;commas,&lt;/strong&gt; &lt;strong&gt;inverted commas&lt;/strong&gt;&amp;nbsp;are&amp;nbsp;&lt;strong&gt;removed,&lt;/strong&gt;&amp;nbsp;and&amp;nbsp;&lt;strong&gt;&amp;#39;that&amp;#39; is&amp;nbsp;added&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;The given &lt;strong&gt;reported speech&lt;/strong&gt; is a &lt;strong&gt;proverb&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;No change is made to the verb&lt;/strong&gt; of the reported speech if it shows &lt;strong&gt;a historical fact, a habitual fact, a universal truth, &lt;/strong&gt;or&lt;strong&gt; a proverb&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;strong&gt;option 1.&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;You may think the past tense form of the verb&lt;strong&gt;&amp;nbsp;&amp;#39;&amp;#39;spoiled&amp;#39;&amp;#39;&amp;nbsp;&lt;/strong&gt;should be used.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Option 3&lt;/strong&gt;&amp;nbsp;is&amp;nbsp;&lt;strong&gt;wrong&amp;nbsp;&lt;/strong&gt;because &lt;strong&gt;&amp;#39;spoiled&amp;#39;&lt;/strong&gt; is used&amp;nbsp;in the past simple tense of the indirect speech.&lt;/li&gt;
	&lt;li&gt;Thus, the correct answer is&lt;strong&gt;&amp;nbsp;option 1.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The following table will enable us to know how tense changes into Indirect speech:-
	&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; dir=&quot;ltr&quot; style=&quot;width:380px;&quot;&gt;
		&lt;colgroup&gt;
			&lt;col width=&quot;422&quot; /&gt;
			&lt;col width=&quot;445&quot; /&gt;
		&lt;/colgroup&gt;
		&lt;tbody&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Direct Speech&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Direct Speech&lt;/strong&gt;&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Indirect Speech&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Indirect Speech&lt;/strong&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present simple (Subject +V1st + Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present simple (Subject + V1st + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject +V2 + Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past simple (Subject + V2 + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present continuous (Subject +is/am/are+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present continuous (Subject + is/am/are + V1 + ing + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past Continuous (Subject + was/were + V1 + ing + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present perfect (Subject + has/have+V3+Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present perfect (Subject + has/have + V3 + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past perfect (Subject + had + V3 + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject+V2+Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past simple (Subject + V2 + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past perfect (Subject + had + V3 + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past Continuous (Subject + was/were + V1 + ing + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect continuous (Subject +had been+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past perfect continuous (Subject + had been + V1 + ing + Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future simple (Subject+ will/shall+V1+object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Future simple (Subject + will/shall + V1 + object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Conditional (Subject+ would+V1+object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Conditional (Subject + would + V1 + object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Future Continuous (Subject + will/shall + be + V1 + ing + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Conditional Continuous (Subject + would + be + V1 + ing + Object)&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;strong&gt;direct speech&lt;/strong&gt;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Direct speech&lt;/strong&gt;&amp;nbsp;को&amp;nbsp;&lt;strong&gt;indirect speech&lt;/strong&gt;&amp;nbsp;में बदलने या बदलने के लिए बुनियादी नियम:
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Commas, inverted commas&lt;/strong&gt;&amp;nbsp;हटा दिए जाते हैं और&amp;nbsp;&lt;strong&gt;&amp;#39;that&amp;#39;&amp;nbsp;&lt;/strong&gt;जोड़ा जाता है।&lt;/li&gt;
		&lt;li&gt;दिया गया reported speech एक कहावत है।&lt;/li&gt;
		&lt;li&gt;रिपोर्ट किए गए भाषण की क्रिया में कोई बदलाव नहीं किया जाता है यदि यह एक &lt;strong&gt;ऐतिहासिक तथ्य, एक अभ्यस्त तथ्य, एक सार्वभौमिक सत्य या एक कहावत&lt;/strong&gt; को दर्शाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&lt;strong&gt;&amp;nbsp;विकल्प 1 है।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;DACB&amp;#39;.&lt;/span&gt;&lt;/p&gt;

