				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past Continuous (Subject +was/were+V1+ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect continuous (Subject +had been+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past perfect continuous (Subject+had been+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 26px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future simple (Subject+ will/shall+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future simple (Subject+ will/shall+V1+object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Conditional (Subject+ would+V1+object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present Conditional (Subject+would+V1+object)&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 29px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Future Continuous (Subject +will/shall+be+V1 +ing+ Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Conditional Continuous (Subject +would+be+V1 +ing+ Object)&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Direct speech&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;indirect speech&lt;/span&gt;&amp;nbsp;में बदलने या बदलने के लिए बुनियादी नियम:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Commas, inverted commas&amp;nbsp;&lt;/span&gt;हटा दिए जाते हैं और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;that&amp;#39;&lt;/span&gt;&amp;nbsp;जोड़ा जाता है, &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;yesterday&lt;/span&gt;&amp;#39; बन जाता है &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;the previous day&lt;/span&gt;&amp;#39;।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Past simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;Subject&amp;nbsp;+&amp;nbsp;V&lt;/span&gt;&lt;span style=&quot;font-weight: 700; position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(came)&amp;nbsp;+ Object&amp;#39;&lt;/span&gt;&amp;nbsp;को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past&amp;nbsp;perfect tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ had + V&lt;/span&gt;&lt;span style=&quot;font-weight: 700; position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;3&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(come)&amp;nbsp;+&amp;nbsp;Object&lt;/span&gt;&amp;#39;&amp;nbsp;में बदल दिया जाएगा।&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 2 है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;is&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The given sentence is saying&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;something about toy shops on either side of the road&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The given sentence is the &lt;strong&gt;present simple tense &lt;/strong&gt;of &lt;strong&gt;passive voice&lt;/strong&gt;&lt;b&gt; &lt;/b&gt;and stating&amp;nbsp;&lt;strong&gt;a fact&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;In the &lt;strong&gt;present simple&lt;/strong&gt;, the &lt;strong&gt;passive&lt;/strong&gt; is: &lt;strong&gt;am / is / are + past participle &lt;/strong&gt;(here, &lt;strong&gt;lined&lt;/strong&gt;).&lt;/li&gt;
	&lt;li&gt;Also, we know that the &lt;strong&gt;singular subject&lt;/strong&gt; will always take &lt;strong&gt;a singular verb&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the &lt;strong&gt;singular verb &amp;#39;is&amp;#39;&lt;/strong&gt; should be used in the blank.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Complete Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;Either side of the road &lt;strong&gt;is&lt;/strong&gt; lined by toy shops&lt;/em&gt;.&lt;br /&gt;
&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Let&lt;/span&gt;&amp;nbsp;us&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;explore&lt;/span&gt;&amp;nbsp;the other&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;options:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Has&lt;/span&gt;&amp;#39;&amp;#39; should be used in the &lt;strong&gt;present perfect tense &lt;/strong&gt;and with a&lt;strong&gt; singular subject&lt;/strong&gt;. (&amp;#39;Has&amp;#39;&amp;nbsp;का प्रयोग present perfect tense ​​में और एकवचन subject के साथ किया जाना चाहिए)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Have&lt;/span&gt;&amp;#39;&amp;#39; should be used in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present perfect tense&amp;nbsp;&lt;/span&gt;and with a&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;plural&amp;nbsp;subject&lt;/span&gt;.&amp;nbsp;(&amp;#39;Have&amp;#39;&amp;nbsp;का प्रयोग&amp;nbsp;present perfect tense&amp;nbsp;​​में और बहुवचन subject के साथ किया जाना चाहिए)&lt;/li&gt;
		&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Are&lt;/span&gt;&amp;#39;&amp;#39; should be used in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&amp;nbsp;&lt;/span&gt;and with a&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;plural subject&lt;/span&gt;.&amp;nbsp;(&amp;#39;Are&amp;#39;&amp;nbsp;का प्रयोग&amp;nbsp;present simple tense&amp;nbsp;​​में और बहुवचन subject के साथ किया जाना चाहिए)&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिया गया वाक्य सड़क के दोनों ओर खिलौनों की दुकानों के बारे में कुछ कह रहा है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य &lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&amp;nbsp;&lt;/span&gt;of&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt; है और एक तथ्य बताता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Present simple&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive&lt;/span&gt; है: &lt;strong&gt;am / is / are + past participle&lt;/strong&gt; (यहाँ, &lt;span style=&quot;font-weight: 700;&quot;&gt;lined&lt;/span&gt;)।&lt;/li&gt;
	&lt;li&gt;साथ ही, हम जानते हैं कि एकवचन &lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt; हमेशा एकवचन &lt;span style=&quot;font-weight: 700;&quot;&gt;verb&lt;/span&gt; लेगा।&lt;/li&gt;
	&lt;li&gt;इसलिए,रिक्त स्थान में एकवचन क्रिया &amp;#39;&lt;strong&gt;is&lt;/strong&gt;&amp;#39; का प्रयोग करना चाहिए।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अत: सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1 है&lt;/span&gt;।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;jockey&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Let us explore the marked&amp;nbsp;option:&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;Jockey&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;a person who rides horses in races, especially as a profession&lt;/strong&gt;. (घुड़दौड़ में भाग लेने वाला घुड़सवार)

		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;A​&lt;span style=&quot;font-weight: 700;&quot;&gt; jockey&lt;/span&gt;&amp;nbsp;must be brave to ride a horse&amp;nbsp;at high speed&lt;/em&gt;.&lt;br /&gt;
			&amp;nbsp;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;&lt;i&gt;.&lt;/i&gt;&lt;br /&gt;
&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Let us explore the other options:
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Porter&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;a person whose job is to carry suitcases, etc. at a railway station, airport, etc&lt;/strong&gt;.&amp;nbsp;(रेलवे स्&amp;zwj;टेशन आदि पर सामान ले जाने वाला व्&amp;zwj;यक्ति; क़ुली)

		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;The &lt;strong&gt;porter&lt;/strong&gt; was weighed down by all the luggage&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Sprinter&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;means&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;an athlete who races over a short distance&lt;/strong&gt;.&amp;nbsp;(एक एथलीट जो कम दूरी पर दौड़ता है)
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;Any half-decent &lt;strong&gt;sprinter&lt;/strong&gt; can run 100m in 11 seconds&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;Flamboyant&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;a person&amp;nbsp;acting in a loud, confident way that attracts attention&lt;/strong&gt;.&amp;nbsp;(भड़कीला व आत्&amp;zwj;मविश्&amp;zwj;वासी और इस कारण ध्यानाकर्षक)
		&lt;ul&gt;
			&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;For example -&amp;nbsp;&lt;/span&gt;&lt;em&gt;The &lt;strong&gt;flamboyant&lt;/strong&gt; singer loves to wear shimmering suits&lt;/em&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;by ink&amp;#39;&amp;nbsp;&lt;/span&gt;i.e.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;this part of the sentence&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;has an error&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;by&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;by&amp;#39;&lt;/span&gt;&amp;nbsp;means&amp;nbsp;&lt;strong&gt;through doing or using something; by means of something&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;in&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;by&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;in&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;used &lt;strong&gt;for stating what you use for writing, drawing, or painting&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;In ink&lt;/span&gt;&amp;#39;&amp;#39; means&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;written or signed with a pen that uses ink, not with a pencil&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 4&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;You need&amp;nbsp;to sign&amp;nbsp;these important documents &lt;strong&gt;in ink&lt;/strong&gt;&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;by&amp;#39;&lt;/span&gt; का प्रयोग गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Preposition &amp;#39;by&amp;#39;&lt;/span&gt; का अर्थ है&amp;nbsp;&lt;strong&gt;के द्वारा; के ज़रिये से&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;इसलिए, &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;in&amp;#39;&lt;/span&gt; का प्रयोग &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;by&amp;#39;&lt;/span&gt; के स्थान पर किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Preposition &amp;#39;in&amp;#39;&lt;/span&gt; का उपयोग यह बताने के लिए किया जाता है कि आप &lt;strong&gt;लेखन, ड्राइंग या पेंटिंग के लिए क्या उपयोग करते हैं&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;&amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;In ink&lt;/span&gt;&amp;#39;&amp;#39; का अर्थ &lt;strong&gt;पेन से लिखा या हस्ताक्षरित है जिसमें स्याही का उपयोग होता है&lt;/strong&gt;, पेंसिल से नहीं।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 4&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;You need&amp;nbsp;to sign&amp;nbsp;these important documents&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in ink&lt;/span&gt;&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;afraid from&amp;#39;&amp;nbsp;&lt;/span&gt;i.e.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;this part of the sentence&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;has an error&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt;&amp;nbsp;is used &lt;strong&gt;for&amp;nbsp;showing the person who sent or gave something&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;of&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;of&amp;#39;&amp;nbsp;&lt;/span&gt;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;used &lt;strong&gt;after some adjectives&lt;/strong&gt; (here, &lt;strong&gt;afraid&lt;/strong&gt;) &lt;strong&gt;for saying a person or thing that a feeling is directed towards&lt;/strong&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;He is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;afraid of&amp;nbsp;&lt;/span&gt;all&amp;nbsp;insects that crawl&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt; का प्रयोग गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Preposition &amp;#39;from&amp;#39;&lt;/span&gt; का प्रयोग उस व्यक्ति को दिखाने के लिए किया जाता है जिसने कुछ भेजा या दिया।&lt;/li&gt;
	&lt;li&gt;इसलिए,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;of&amp;#39;&lt;/span&gt; का प्रयोग &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;from&amp;#39;&lt;/span&gt; के स्थान पर किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;किसी व्यक्ति या बात को कहने के लिए जिसकी ओर एक भावना निर्देशित होती है,&amp;nbsp;कुछ adjectives (यहां, afraid) के बाद preposition &amp;#39;of&amp;#39; का प्रयोग किया जाता है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;He is &lt;strong&gt;afraid of &lt;/strong&gt;all insects that crawl&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;We hold all meetings in the conference room&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is in&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&amp;nbsp;&lt;/span&gt;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;When we convert this sentence into an&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;, the subject &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;All meetings&lt;/span&gt;&amp;#39; of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive&amp;nbsp;voice&lt;/span&gt;&amp;nbsp;becomes the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;object&lt;/span&gt;, the &lt;strong&gt;hidden&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;us&lt;/span&gt;&amp;#39; becomes the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject &amp;#39;We&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The passive format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;are&amp;nbsp;+ V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;held&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the active format &amp;quot;&lt;strong&gt;V1&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(hold)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;active and passive voice&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

