&lt;p&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past simple tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;जब हम इस वाक्य को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;में बदलते हैं, तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;का&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;The building&amp;#39;&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&lt;/span&gt;&amp;nbsp;बन जाता है&amp;nbsp;और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;special commandos&lt;/span&gt;&amp;#39;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;बन जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;was + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;surrounded&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V2&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(surrounded)&lt;/span&gt;&amp;quot;&amp;nbsp;में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past simple tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;No substitution&lt;/span&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the underlined segment of the sentence,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;no substitution is required&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;strong&gt;Lest...should&lt;/strong&gt;&amp;#39; is used &lt;strong&gt;to extend a warning and also suggest the consequences of not paying attention to that warning&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The use of the conjunction &amp;#39;&lt;strong&gt;lest&lt;/strong&gt;&amp;#39;&amp;nbsp;in any sentence &lt;strong&gt;conveys a negative sense&lt;/strong&gt; as such, &lt;strong&gt;&amp;#39;no&amp;#39;&lt;/strong&gt; or &lt;strong&gt;&amp;#39;not&amp;#39;&lt;/strong&gt; &lt;strong&gt;should not be used in that sentence&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;strong&gt;Lest...should&lt;/strong&gt;&amp;#39; already &lt;strong&gt;conveys a negative sense&lt;/strong&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;Don&amp;rsquo;t lose sight of your goal lest you should fail&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;em&gt;&lt;strong&gt;&amp;#39;Lest&amp;#39;&amp;nbsp;&lt;/strong&gt;is always &lt;strong&gt;followed by &amp;#39;should&amp;#39;&lt;/strong&gt;.&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;&lt;em&gt;&amp;#39;&lt;strong&gt;Should&lt;/strong&gt;&amp;#39; here &lt;strong&gt;can not be replaced by&lt;/strong&gt; &amp;#39;&lt;strong&gt;would&lt;/strong&gt;&amp;#39; or &amp;#39;&lt;strong&gt;may&lt;/strong&gt;&amp;#39;.&lt;/em&gt;&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वाक्य के रेखांकित खंड में किसी प्रतिस्थापन की आवश्यकता नहीं है।&lt;/li&gt;
	&lt;li&gt;चेतावनी देने के लिए &amp;#39;&lt;strong&gt;Lest... should&lt;/strong&gt;&amp;#39; का उपयोग किया जाता है और उस चेतावनी पर ध्यान न देने के परिणामों का भी सुझाव दिया जाता है।&lt;/li&gt;
	&lt;li&gt;किसी भी वाक्य में conjunction &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;lest&lt;/span&gt;&amp;#39; का प्रयोग एक नकारात्मक भाव को व्यक्त करता है जैसे कि उस वाक्य में &amp;#39;नहीं&amp;#39;&amp;nbsp;का प्रयोग नहीं किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;&amp;#39;&lt;strong&gt;Lest...should&lt;/strong&gt;&amp;#39; पहले से ही &lt;strong&gt;एक नकारात्मक भाव&lt;/strong&gt; व्यक्त करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;Don&amp;rsquo;t lose sight of your goal lest you should fail&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ADECBF&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The sentence &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;A&lt;/span&gt;&amp;#39;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;independent&lt;/span&gt;&amp;nbsp;of any other sentence as it is giving general information about&amp;nbsp;&amp;quot;&lt;b&gt;Toto monkey and his bathing arrangement&lt;/b&gt;&amp;quot;. Hence, &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;A&lt;/span&gt;&amp;#39; is the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;first part&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;D&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;A&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;what&amp;nbsp;the monkey did&amp;nbsp;with the warm water&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;E&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;D&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;what the monkey does after checking the temperature of the water&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;C&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;E&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;what the monkey does when the water becomes cold&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;B&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;C&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;strong&gt;where the monkey runs straight away after bath and what he does there&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The sentence &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;F&lt;/span&gt;&amp;#39;&amp;nbsp;is the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;concluding&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;part&lt;/span&gt;&amp;nbsp;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;how he feels when someone mocks him for such activities&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u style=&quot;font-weight: 700;&quot;&gt;Paragraph after rearranging the sentences&lt;/u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&amp;nbsp;&lt;/span&gt;&lt;em&gt;A great treat for Toto monkey in cold weather was the large bowl of warm water given to him for his bath.&amp;nbsp;He would cunningly test the temperature with his hand and then step into the bath gradually.&amp;nbsp;Once comfortable, he would take the soap in his hands or feet and rub himself all over.&amp;nbsp;When the water became cold, he would get out and run as quickly as he could.&amp;nbsp;He would then rush straight to the kitchen fire to dry himself.&amp;nbsp;But if anyone made fun of his activities, he would feel hurt.&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hint-text-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hint&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;Important Rules to Solve the Para Jumbles&lt;/u&gt;:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Read the sentences&lt;/span&gt;&amp;nbsp;attentively and try to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;comprehend the idea or theme of the sentence&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;eliminate the irrelevant&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;options.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Try to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;identify the opening&amp;nbsp;&lt;/span&gt;(independent sentence)&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;and closing sentences&amp;nbsp;&lt;/span&gt;(concluding sentence)&lt;span style=&quot;font-weight: 700;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Try to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;identify the mandatory pairs&lt;/span&gt;. Two sentences can be connected through various connectors and other determinants.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वाक्य &amp;#39;A&amp;#39; किसी अन्य वाक्य से स्वतंत्र है क्योंकि यह&amp;nbsp;&amp;quot;टोटो बंदर और उसकी स्नान व्यवस्था&amp;quot;&amp;nbsp;के बारे में सामान्य जानकारी दे रहा है। अतः &amp;#39;A&amp;#39; पहला भाग है।&lt;/li&gt;
	&lt;li&gt;वाक्य D, A के बाद आएगा क्योंकि यह बताता है कि बंदर ने गर्म पानी के साथ क्या किया।&lt;/li&gt;
	&lt;li&gt;वाक्य E, D के बाद आएगा क्योंकि यह बताता है कि बंदर पानी का तापमान जांचने के बाद क्या करता है।&lt;/li&gt;
	&lt;li&gt;वाक्य C, E&amp;nbsp;के बाद आएगा क्योंकि यह बताता है कि पानी ठंडा होने पर बंदर क्या करता है।&lt;/li&gt;
	&lt;li&gt;वाक्य B, C के बाद आएगा क्योंकि यह बताता है कि बंदर नहाने के बाद सीधे कहां भागता है और वहां क्या करता है।&lt;/li&gt;
	&lt;li&gt;वाक्य &amp;#39;F&amp;#39; अंतिम भाग है क्योंकि यह बताता है कि जब कोई उसकी ऐसी गतिविधियों के लिए उसका मजाक उड़ाता है तो वह कैसा महसूस करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;AEDCBF&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The sentence &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;A&lt;/span&gt;&amp;#39;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;independent&lt;/span&gt;&amp;nbsp;of any other sentence as it is giving general information about&amp;nbsp;&amp;quot;&lt;strong&gt;Dr. Sadao Hoki&amp;rsquo;s house&lt;/strong&gt;&amp;quot;. Hence, &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;A&lt;/span&gt;&amp;#39; is the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;first part&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;E&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;A&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;b&gt;the setup of the doctor&amp;#39;s house&lt;/b&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;D&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;E&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;what Dr. Sadao used to do in the South Seas when he was a child&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;C&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;D&amp;nbsp;&lt;/span&gt;because it explains &lt;b&gt;what the doctor&amp;#39;s father used to do with the doctor&lt;/b&gt;.&lt;/li&gt;
	&lt;li&gt;Sentence&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;B&amp;nbsp;&lt;/span&gt;will come after&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;C&amp;nbsp;&lt;/span&gt;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;what the doctor&amp;#39;s father&amp;nbsp;said about the islands of the South Seas&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The sentence &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;F&lt;/span&gt;&amp;#39;&amp;nbsp;is the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;concluding&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;part&lt;/span&gt;&amp;nbsp;because it explains&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;what the doctor finally asked his father.&lt;/span&gt;&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u style=&quot;font-weight: 700;&quot;&gt;Paragraph after rearranging the sentences&lt;/u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&amp;nbsp;&lt;/span&gt;&lt;em&gt;Dr. Sadao Hoki&amp;rsquo;s house was built on a spot on the Japanese coast where he had played as a little boy.&amp;nbsp;The square stone house was set upon rocks above a beach outlined with bent pines.&amp;nbsp;As a boy, Sadao had climbed the pines, supporting himself on his bare feet as the men did in the South Seas.&amp;nbsp;His father had taken him to the islands of those seas and taught him things he had not forgotten.&amp;nbsp;His father had said, &amp;ldquo;Those islands are the stepping stones to the future for Japan.&amp;nbsp;&amp;ldquo;Where shall we step from them?&amp;rdquo; Sadao had asked seriously.&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hint-text-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hint&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;Important Rules to Solve the Para Jumbles&lt;/u&gt;:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Read the sentences&lt;/span&gt;&amp;nbsp;attentively and try to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;comprehend the idea or theme of the sentence&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;eliminate the irrelevant&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;options.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Try to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;identify the opening&amp;nbsp;&lt;/span&gt;(independent sentence)&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;and closing sentences&amp;nbsp;&lt;/span&gt;(concluding sentence)&lt;span style=&quot;font-weight: 700;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Try to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;identify the mandatory pairs&lt;/span&gt;. Two sentences can be connected through various connectors and other determinants.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वाक्य &amp;#39;A&amp;#39; किसी अन्य वाक्य से स्वतंत्र है क्योंकि यह&amp;nbsp;&amp;quot;डॉ. सदाओ होकी के घर&amp;quot;&amp;nbsp;के बारे में सामान्य जानकारी दे रहा है। अतः &amp;#39;A&amp;#39; पहला भाग है।&lt;/li&gt;
	&lt;li&gt;वाक्य E, A के बाद आएगा क्योंकि यह डॉक्टर के घर की व्यवस्था की व्याख्या करता है।&lt;/li&gt;
	&lt;li&gt;वाक्य D, E के बाद आएगा क्योंकि यह बताता है कि डॉ. सदाओ जब बच्चा था तब दक्षिण समुद्र में क्या किया करता था।&lt;/li&gt;
	&lt;li&gt;वाक्य C, D&amp;nbsp;के बाद आएगा&amp;nbsp;क्योंकि यह बताता है कि डॉक्टर के पिता डॉक्टर के साथ क्या करते थे।&lt;/li&gt;
	&lt;li&gt;वाक्य B, C के बाद आएगा क्योंकि यह बताता है कि डॉक्टर के पिता ने दक्षिण समुद्र के द्वीपों के बारे में क्या कहा।&lt;/li&gt;
	&lt;li&gt;वाक्य &amp;#39;F&amp;#39; अंतिम भाग है क्योंकि यह बताता है कि डॉक्टर ने अपने पिता से आखिर में क्या पूछा।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;than you knows&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;None other&amp;#39; and &amp;#39;than&amp;#39; are &lt;strong&gt;correlative conjunctions&lt;/strong&gt; i.e., they are always used in pairs.

	&lt;ul&gt;
		&lt;li&gt;​For example: None other than you is invited to the meeting.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;In this question, &amp;quot;none other than&amp;quot; is a phrase that means &amp;quot;no one else except for.&amp;quot;&lt;/li&gt;
	&lt;li&gt;The subject of the sentence is &amp;quot;none,&amp;quot; which is a &lt;strong&gt;singular noun&lt;/strong&gt;. The verb should agree with the singular subject, so &amp;quot;knows&amp;quot; is the correct verb form.&lt;/li&gt;
	&lt;li&gt;Therefore, &amp;quot;than you knows&amp;quot; is the correct form of the verb in this sentence. &amp;quot;Beside&amp;quot; is not the correct preposition to use in this sentence as &amp;quot;none other than&amp;quot; already implies that there is no one else beside the person being referred to.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Therefore, the correct answer is: &lt;strong&gt;than you knows.&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;
	&lt;p&gt;In this sentence, the verb &lt;strong&gt;knows &lt;/strong&gt;does not agree with &lt;strong&gt;you&lt;/strong&gt;, but with &lt;strong&gt;none&lt;/strong&gt;.&lt;br /&gt;
	&lt;strong&gt;None &lt;/strong&gt;is a singular indefinite pronoun that can mean no one or not any.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;In this sentence, &lt;strong&gt;none &lt;/strong&gt;means &lt;strong&gt;no one&lt;/strong&gt;, and it is the subject of the verb knows. The phrase &lt;strong&gt;than you &lt;/strong&gt;is not the subject, but a complement that shows the comparison.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;Therefore, the verb &lt;strong&gt;knows &lt;/strong&gt;agrees with the singular subject &lt;strong&gt;none&lt;/strong&gt;, not the second person pronoun &lt;strong&gt;you&lt;/strong&gt;.&lt;/p&gt;

	&lt;ul&gt;
		&lt;li&gt;
		&lt;p&gt;For example, you can say:&lt;strong&gt;None of us knows the answer. &lt;/strong&gt;(&lt;strong&gt;None &lt;/strong&gt;is the subject and &lt;strong&gt;knows &lt;/strong&gt;is the verb. &lt;strong&gt;Of us&lt;/strong&gt; is a prepositional phrase that modifies none.)&lt;/p&gt;
		&lt;/li&gt;
		&lt;li&gt;
		&lt;p&gt;&lt;strong&gt;He knows more than you. (&lt;/strong&gt;He is the subject and &lt;strong&gt;knows &lt;/strong&gt;is the verb. &lt;strong&gt;Than you&lt;/strong&gt; is a complement that shows the comparison.)&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;did the chairman arrived&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;i.e.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;this part of the sentence&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;has an error&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past form of the verb &amp;#39;arrived&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;auxiliary verb &amp;#39;did&amp;#39;&lt;/strong&gt;&amp;nbsp;is marked for &lt;strong&gt;past tense&lt;/strong&gt;, but the &lt;strong&gt;main verb&lt;/strong&gt; appears &lt;strong&gt;in its base form&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;We know that the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;verb that follows&lt;/span&gt;&amp;nbsp;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;did&lt;/span&gt;&amp;#39;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in its base form&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Therefore, the &lt;strong&gt;base form of the verb &amp;#39;arrive&amp;#39;&lt;/strong&gt; should be used &lt;strong&gt;in place of&lt;/strong&gt; the &lt;strong&gt;past tense form of the verb &amp;#39;arrived&amp;#39;&lt;/strong&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;No sooner &lt;strong&gt;did the chairman arrive&lt;/strong&gt; than the&amp;nbsp;proceedings commenced&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में &lt;span style=&quot;font-weight: 700;&quot;&gt;past form of the verb &amp;#39;arrived&amp;#39;&lt;/span&gt; का प्रयोग गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Auxiliary verb &amp;#39;did&amp;#39;&lt;/span&gt; &lt;strong&gt;भूतकाल &lt;/strong&gt;के लिए चिह्नित है, लेकिन &lt;strong&gt;मुख्य क्रिया&lt;/strong&gt; अपने &lt;strong&gt;मूल रूप&lt;/strong&gt; में प्रकट होती है।&lt;/li&gt;
	&lt;li&gt;हम जानते हैं कि &amp;#39;&lt;strong&gt;did&lt;/strong&gt;&amp;#39; &lt;strong&gt;के बाद आने वाली क्रिया&lt;/strong&gt; को उसके &lt;strong&gt;मूल रूप में&lt;/strong&gt; प्रयोग किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;इसलिए &lt;span style=&quot;font-weight: 700;&quot;&gt;past tense form of the verb &amp;#39;arrived&amp;#39;&lt;/span&gt; के स्थान पर &lt;span style=&quot;font-weight: 700;&quot;&gt;base form of the verb &amp;#39;arrive&amp;#39;&lt;/span&gt; का प्रयोग किया जाना चाहिए।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;No sooner&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;did the chairman arrive&lt;/span&gt;&amp;nbsp;than the&amp;nbsp;proceedings commenced&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;As soon he heard&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;i.e.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;this part of the sentence&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;has an error&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;phrase &amp;#39;&amp;#39;As soon&amp;#39;&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;phrase &amp;#39;&amp;#39;As soon as&amp;#39;&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;phrase &amp;#39;&amp;#39;As soon&amp;#39;&amp;#39;&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The given sentence is saying about &lt;strong&gt;someone hiding just after hearing the sound of thunder&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;phrase &amp;#39;&amp;#39;As soon as&amp;#39;&amp;#39; &lt;/strong&gt;means&amp;nbsp;&lt;strong&gt;immediately after something has happened&lt;/strong&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;&lt;strong&gt;As soon as he heard&lt;/strong&gt; the sound of thunder, he hid under the bed&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में &lt;span style=&quot;font-weight: 700;&quot;&gt;phrase &amp;#39;&amp;#39;As soon&amp;#39;&amp;#39;&lt;/span&gt; का प्रयोग गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Phrase &amp;#39;&amp;#39;As soon&amp;#39;&amp;#39;&lt;/span&gt; के स्थान पर &lt;span style=&quot;font-weight: 700;&quot;&gt;phrase &amp;#39;&amp;#39;As soon as&amp;#39;&amp;#39;&lt;/span&gt; का प्रयोग किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य कह रहा है कि कोई गड़गड़ाहट की आवाज सुनकर ही छिप गया।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Phrase &amp;#39;&amp;#39;As soon as&amp;#39;&amp;#39;&lt;/span&gt; का अर्थ है &lt;strong&gt;कुछ घटित होने के तुरंत बाद&lt;/strong&gt;।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;As soon as he heard&lt;/span&gt;&amp;nbsp;the sound of thunder, he hid under the bed&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;All my friends trust me&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is in&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&amp;nbsp;&lt;/span&gt;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;When we convert this sentence into an&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;, the &lt;strong&gt;subject&lt;/strong&gt; &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;I&lt;/span&gt;&amp;#39; of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive&amp;nbsp;voice&lt;/span&gt;&amp;nbsp;becomes the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;object &amp;#39;me&amp;#39;&lt;/span&gt;, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;All my friends&lt;/span&gt;&amp;#39; becomes the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The passive format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;am + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;trusted&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the active format &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V1&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(trust)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Verbs of passive format have a different set of tenses (*V3 - Past participle or Third form of the Verb) as given below in the table:&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; dir=&quot;ltr&quot; style=&quot;background-color: rgb(255, 255, 255); width: 330px;&quot; xmlns=&quot;http://www.w3.org/1999/xhtml&quot;&gt;
	&lt;colgroup&gt;
		&lt;col width=&quot;183&quot; /&gt;
		&lt;col width=&quot;221&quot; /&gt;
		&lt;col width=&quot;156&quot; /&gt;
		&lt;col width=&quot;246&quot; /&gt;
	&lt;/colgroup&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;           TENSE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;TENSE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;            ACTIVE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ACTIVE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;          PASSIVE&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;PASSIVE&lt;/span&gt;&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;      PASSIVE CONVERSION&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;PASSIVE CONVERSION&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Simple&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Simple&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He plays football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He plays football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;am/is/are + V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;am/is/are + V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football is played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Continuous&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Continuous&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He is playing football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He is playing football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;am/is/are + being +V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;am/is/are + being +V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football is being played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football is being played by him&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present Perfect&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Present Perfect&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;He has played football&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;He has played football&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Has/have + been+ V3&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Has/have + been+ V3&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Football has been played by him&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Football has been played by him&lt;/td&gt;
