&lt;p&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;br /&gt;
&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;जब हम इस वाक्य को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;में बदलते हैं, तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;का&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;I&amp;#39;&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object &amp;#39;me&amp;#39;&lt;/span&gt;&amp;nbsp;बन जाता है&amp;nbsp;और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;All my friends&lt;/span&gt;&amp;#39;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;बन जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;am + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;trusted&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V1&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;(trust)&lt;/span&gt;&amp;quot;&amp;nbsp;में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 3&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;strong&gt;He asked me what he could do for me&lt;/strong&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given sentence&lt;/span&gt;&amp;nbsp;is a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;direct speech&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;basic rules&lt;/span&gt;&amp;nbsp;for changing or&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converting direct speech into indirect speech:&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;commas, inverted commas&lt;/span&gt;&amp;nbsp;are&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;removed&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;The reporting verb &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;said to&lt;/span&gt;&amp;#39;&amp;#39; becomes &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;asked&lt;/span&gt;&amp;#39;&amp;#39; and the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;question mark (?) becomes&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;full stop (.)&lt;/span&gt;.&lt;/li&gt;
		&lt;li&gt;The first-person pronoun &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;I&lt;/span&gt;&amp;#39;&amp;#39; becomes the third-person pronoun &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;he&lt;/span&gt;&amp;#39;&amp;#39; and&amp;nbsp;the second-person pronoun &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;you&lt;/span&gt;&amp;#39;&amp;#39; becomes the first-person pronoun &amp;#39;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;me&lt;/span&gt;&amp;#39;&amp;#39;.&lt;/li&gt;
		&lt;li&gt;The&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;present simple tense&lt;/span&gt;&amp;nbsp;format&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+&amp;nbsp;V&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;1&lt;/span&gt;&amp;nbsp;(can)&amp;nbsp;+ Object&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;will be changed into&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;past&amp;nbsp;simple tense&lt;/span&gt;&amp;nbsp;format &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Subject&amp;nbsp;+ V&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&amp;nbsp;&lt;/span&gt;(could)&amp;nbsp;+&amp;nbsp;Object&lt;/span&gt;&amp;#39;.&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/confusion-points-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Confusion Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;You may think the pronouns in other options&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;should be used but the pronouns used in the first option are correctly used.&lt;/li&gt;
	&lt;li&gt;Thus, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 1&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The following table will enable us to know how tense changes into Indirect speech:-
	&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; dir=&quot;ltr&quot; style=&quot;width: 0px; border: none;&quot; xmlns=&quot;http://www.w3.org/1999/xhtml&quot;&gt;
		&lt;colgroup&gt;
			&lt;col width=&quot;422&quot; /&gt;
