			&lt;tr style=&quot;height: 21px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Direct Speech&amp;quot;}&quot; style=&quot;padding: 2px 3px; border: 1px solid rgb(0, 0, 0); overflow: hidden; vertical-align: bottom; text-align: center; background-color: rgb(102, 255, 255);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Direct Speech&lt;/span&gt;&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Indirect Speech&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center; background-color: rgb(102, 255, 255);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Indirect Speech&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr style=&quot;height: 27px;&quot;&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Present simple  (Subject +V1st + Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Present simple (Subject +V1st + Object)&lt;/td&gt;
				&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past simple (Subject +V2 + Object)&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 1px; border-style: solid; overflow: hidden; vertical-align: bottom; text-align: center;&quot;&gt;Past simple (Subject +V2 + Object)&lt;/td&gt;
			&lt;/tr&gt;
