&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice में&lt;/span&gt;&amp;nbsp;, एक वाक्य विषय पर जोर देता है, एक क्रिया करता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice में&lt;/span&gt;&amp;nbsp;, एक वाक्य वाक्य की क्रिया या वस्तु पर जोर देता है।&lt;/li&gt;
	&lt;li&gt;दिया गया वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;में है और यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;जब हम इस वाक्य को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;&amp;nbsp;में बदलते हैं, तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;का&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;People&amp;#39;&lt;/span&gt;, &lt;strong&gt;hidden&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&lt;/span&gt;&amp;nbsp;बन जाता है&amp;nbsp;और&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object &amp;#39;he&amp;#39;&lt;/span&gt;,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;&amp;nbsp;बन जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;V1&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;(&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;say&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; को&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;is + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;said&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot;&amp;nbsp;में परिवर्तित किया जाना चाहिए।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;present simple tense&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;है।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;for handle&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;i.e.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;this part of the sentence&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;has an error&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In the given sentence, the use of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;for&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;incorrect&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;for&amp;#39;&lt;/span&gt;&amp;nbsp;is&amp;nbsp;used &lt;strong&gt;before&lt;/strong&gt; the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;present participle or gerund form of the verb&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;to-infinitive&lt;/strong&gt; is used &lt;strong&gt;for expressing the purpose of something or someone&amp;#39;s opinion about something&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;to-infinitive&lt;/strong&gt; is: &lt;strong&gt;to + base form of the verb &lt;/strong&gt;(here,&lt;strong&gt; handle&lt;/strong&gt;).&lt;/li&gt;
	&lt;li&gt;Therefore, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;to&amp;#39;&lt;/span&gt;&amp;nbsp;should be used&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;in place of&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;for&amp;#39;&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Correct Sentence:&lt;/span&gt;&amp;nbsp;&lt;em&gt;He is&amp;nbsp;too immature&amp;nbsp;&lt;strong&gt;to&lt;/strong&gt; &lt;strong&gt;handle&lt;/strong&gt;&amp;nbsp;the situation&lt;/em&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/hinglish-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Hinglish&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए वाक्य में &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;for&amp;#39;&lt;/span&gt; का प्रयोग गलत है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Verb &lt;/strong&gt;के &lt;strong&gt;present participle &lt;/strong&gt;या&lt;strong&gt; gerund&lt;/strong&gt;&amp;nbsp;रूप से पहले &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;for&amp;#39;&lt;/span&gt; का उपयोग किया जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;To-infinitive&lt;/span&gt; का उपयोग &lt;strong&gt;किसी चीज़ के उद्देश्य या किसी चीज़ के बारे में किसी की राय व्यक्त करने के लिए&lt;/strong&gt; किया जाता है।&lt;/li&gt;
	&lt;li&gt;To-infinitive: &lt;span style=&quot;font-weight: 700;&quot;&gt;to + base form of the verb&lt;/span&gt; (यहाँ, &lt;span style=&quot;font-weight: 700;&quot;&gt;handle&lt;/span&gt;)।&lt;/li&gt;
	&lt;li&gt;इसलिए, &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;for&amp;#39;&lt;/span&gt; के ​​स्थान पर &lt;span style=&quot;font-weight: 700;&quot;&gt;preposition &amp;#39;to&amp;#39;&lt;/span&gt; का प्रयोग किया जाना चाहिए।&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 2&lt;/span&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सही वाक्य:&amp;nbsp;&lt;/span&gt;&lt;em&gt;He is&amp;nbsp;too immature&amp;nbsp;&lt;strong&gt;to&lt;/strong&gt; &lt;strong&gt;handle&lt;/strong&gt;&amp;nbsp;the situation.&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;freedom to do what one wants&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Given Idiom:&amp;nbsp;&lt;/span&gt;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Elbow room&lt;/span&gt;&lt;/em&gt;&amp;nbsp;means &lt;strong&gt;the freedom and ability to act as one wants&lt;/strong&gt;.&amp;nbsp;(जैसा चाहे वैसा कार्य करने की स्वतंत्रता और क्षमता)

	&lt;ul&gt;
		&lt;li&gt;&lt;em&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&amp;nbsp;&lt;/span&gt;I can hardly move. Give me some &lt;strong&gt;elbow room&lt;/strong&gt;&lt;/em&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;From the given options, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;third option&lt;/span&gt;&amp;nbsp;is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;most appropriate meaning of the given idiom.&lt;/span&gt;&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;option 3&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;We may think from the phrase &amp;quot;Elbow room&amp;quot;&amp;nbsp;that&amp;nbsp;it is all about some type of room.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;
	&lt;p&gt;&amp;nbsp;&lt;em&gt;This metaphor for having enough space to extend one&amp;rsquo;s elbows has been used since the sixteenth century&lt;/em&gt;.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;You will not be helped by anybody if you are rude&lt;/strong&gt;.&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Active Voice&lt;/span&gt;, a sentence emphasizes the subject,&amp;nbsp;performing an action.&lt;/li&gt;
	&lt;li&gt;In&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Passive Voice&lt;/span&gt;, a sentence emphasizes the action or the object of the sentence.&lt;/li&gt;
	&lt;li&gt;The given sentence is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;and it is in the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;future simple tense&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;When we convert this sentence into a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive voice&lt;/span&gt;, the &lt;strong&gt;subject&lt;/strong&gt; &amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;Nobody&lt;/span&gt;&amp;#39; of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active voice&lt;/span&gt;&amp;nbsp;becomes the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;object &amp;#39;anybody&amp;#39;&lt;/span&gt;, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;object&amp;nbsp;&lt;/span&gt;&amp;#39;&lt;span style=&quot;font-weight: 700;&quot;&gt;you&lt;/span&gt;&amp;#39; becomes the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;subject&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;active format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;will + V1&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;(&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;help&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot; should be&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;converted into&lt;/span&gt;&amp;nbsp;the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;passive format&lt;/span&gt;&amp;nbsp;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;will + be + V3 (&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;helped&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;)&lt;/span&gt;&amp;quot;.&lt;/li&gt;
	&lt;li&gt;This&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;active and passive voice&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;rule&lt;/span&gt;&amp;nbsp;for the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;future simple tense&lt;/span&gt;.&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence, the correct answer is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;option 4&lt;/span&gt;.&lt;/p&gt;

